"use client"

import React, { useState } from 'react';
import axios from 'axios';
// import { BACK_BASIC_URL } from '@/commonApis'; // 이전에 만든 공통 주소가 있다면 사용하세요!
import styles from './drug.module.css'; // CSS 파일 연동

// 백엔드 Entity와 똑같은 구조로 타입(그릇)을 만들어줍니다.
interface DrugItem {
    itemSeq: string;
    itemName: string;
    entpName: string;
    efficacy: string;
    useMethod: string;
    caution: string;
    itemImage: string | null;
}

export default function DrugSearchPage() {
    const [keyword, setKeyword] = useState('');
    const [results, setResults] = useState<DrugItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState<string | null>(null);

    const handleSearch = async () => {
        // 검색어 입력 확인 (빈칸 방지)
        if (!keyword.trim()) {
            setErrorMsg("약 이름을 입력해주세요. (예: 타이레놀)");
            return;
        }

        setErrorMsg(null);
        setLoading(true);

        try {
            // ⭐️ 백엔드로 검색 요청을 보냅니다!
            // BACK_BASIC_URL 상수가 있다면 `http://localhost:8088` 대신 사용하세요.
            const response = await axios.get(`http://localhost:8088/api/drug/search?keyword=${keyword}`);
            setResults(response.data);
            
        } catch (error) {
            console.error("검색 실패:", error);
            setErrorMsg("서버와 연결할 수 없습니다. 백엔드 서버가 켜져 있는지 확인해주세요.");
        } finally {
            setLoading(false);
        }
    };

    // 엔터키 쳤을 때도 검색되게 하는 센스!
    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') handleSearch();
    };

    return (
        <div className={styles.container}>
            <h2 className={styles.title}>💊 스마트 약 검색 (e약은요)</h2>
            
            {/* 🔍 검색창 영역 */}
            <div className={styles.searchBox}>
                <input 
                    type="text" 
                    placeholder="약 이름을 입력하세요" 
                    value={keyword}
                    onChange={(e) => {
                        setKeyword(e.target.value);
                        if (errorMsg) setErrorMsg(null); // 타이핑 시작하면 에러메시지 지우기
                    }}
                    onKeyDown={handleKeyDown}
                    className={styles.input}
                />
                <button onClick={handleSearch} className={styles.btn}>검색</button>
            </div>

            {/* 🚨 에러 메시지 출력 영역 */}
            {errorMsg && <p className={styles.errorMessage}>🚨 {errorMsg}</p>}

            {/* 📋 결과 출력 영역 */}
            <div className={styles.resultArea}>
                {loading ? (
                    <p className={styles.message}>약을 찾고 있습니다... 🔍<br/>(DB에 없으면 식약처에서 가져옵니다)</p>
                ) : results.length > 0 ? (
                    <div className={styles.grid}>
                        {results.map((drug, index) => (
                            <div key={index} className={styles.card}>
                                <div className={styles.imgWrapper}>
                                    {/* 이미지가 없으면 준비된 기본 이미지(no_drug_img.png) 띄우기 */}
                                    <img 
                                        src={drug.itemImage || "/img/no_drug_img.png"} 
                                        alt={drug.itemName} 
                                        onError={(e) => e.currentTarget.src = "/img/no_drug_img.png"}
                                    />
                                </div>
                                <div className={styles.content}>
                                    <span className={styles.company}>{drug.entpName}</span>
                                    <h3 className={styles.drugName}>{drug.itemName}</h3>
                                    
                                    <div className={styles.info}>
                                        <strong>효능/효과:</strong> 
                                        {/* 내용이 너무 길면 잘라서 보여주기 */}
                                        <p>{drug.efficacy && drug.efficacy.length > 80 
                                            ? drug.efficacy.substring(0, 80) + "..." 
                                            : drug.efficacy}
                                        </p>
                                    </div>
                                    <div className={styles.info}>
                                        <strong>용법/용량:</strong> 
                                        <p>{drug.useMethod && drug.useMethod.length > 50 
                                            ? drug.useMethod.substring(0, 50) + "..." 
                                            : drug.useMethod}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    // 검색 전이거나 결과가 없을 때
                    !loading && keyword && <p className={styles.message}>검색 결과가 없습니다.</p>
                )}
            </div>
        </div>
    );
}